import React, { useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { addAssignment } from '../redux/assignmentsReducer';

const AssignmentForm = ({ courseId }) => {
  const [title, setTitle] = useState('');
  const { user } = useSelector((state) => state.auth);
  const dispatch = useDispatch();

  const handleSubmit = async (e) => {
    e.preventDefault();
    const newAssignment = { courseId, title, studentId: user.id, status: 'submitted' };
    const response = await fetch('http://localhost:3001/assignments', {
      method: 'POST',
      body: JSON.stringify(newAssignment),
      headers: { 'Content-Type': 'application/json' },
    });
    const data = await response.json();
    dispatch(addAssignment(data));
    setTitle('');
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        type="text"
        value={title}
        onChange={(e) => setTitle(e.target.value)}
        placeholder="Assignment Title"
      />
      <button type="submit">Submit Assignment</button>
    </form>
  );
};

export default AssignmentForm;
